public class Solution {

    public List<List<Integer>> findMinMax(TreeNode root, int[] queries) {
        if (root == null) {
            return new ArrayList<>();
        }

        List<List<Integer>> ans = new ArrayList<>();
        for (int query : queries) {
            TreeNode node = root;
            List<Integer> currentList = Arrays.asList(-1, -1);

            // Find the minimum value less than or equal to the query
            while (node != null && node.val < query) {
                if (currentList.get(0) == -1 || node.val > currentList.get(0)) {
                    currentList.set(0, node.val);
                }
                node = node.right;
            }

            // Find the maximum value greater than or equal to the query
            while (node != null && node.val >= query) {
                if (currentList.get(1) == -1 || node.val < currentList.get(1)) {
                    currentList.set(1, node.val);
                }
                node = node.left;
            }

            ans.add(currentList);
        }
        return ans;
    }
}

